public class BackgroundOrderProcessor : BackgroundService
{
    private readonly IServiceProvider _serviceProvider;
    private readonly ILogger<BackgroundOrderProcessor> _logger;
    private readonly Channel<int> _orderChannel;

    public BackgroundOrderProcessor(
        IServiceProvider serviceProvider,
        ILogger<BackgroundOrderProcessor> logger,
        Channel<int> orderChannel)
    {
        _serviceProvider = serviceProvider;
        _logger = logger;
        _orderChannel = orderChannel;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        await foreach (var orderId in _orderChannel.Reader.ReadAllAsync(stoppingToken))
        {
            try
            {
                await ProcessOrderAsync(orderId, stoppingToken);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error processing order {OrderId}", orderId);
            }
        }
    }

    private async Task ProcessOrderAsync(int orderId, CancellationToken ct)
    {
        using var scope = _serviceProvider.CreateScope();
        var orderService = scope.ServiceProvider.GetRequiredService<IOrderService>();
        await orderService.ProcessAsync(orderId, ct);
    }
}

public class CleanupService : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromHours(1));
        while (!stoppingToken.IsCancellationRequested &&
               await timer.WaitForNextTickAsync(stoppingToken))
        {
            try { await DoCleanupAsync(stoppingToken); }
            catch (Exception ex) { _logger.LogError(ex, "Cleanup failed"); }
        }
    }
}

// Program.cs
builder.Services.AddSingleton(Channel.CreateBounded<int>(
    new BoundedChannelOptions(1000) { FullMode = BoundedChannelFullMode.Wait }));
builder.Services.AddSingleton<OrderProcessorHealth>();
builder.Services.AddHostedService<BackgroundOrderProcessor>();
builder.Services.AddHealthChecks()
    .AddCheck<OrderProcessorHealth>("order-processor");

// OrderProcessorHealth.cs
public class OrderProcessorHealth : IHealthCheck
{
    public DateTime LastSuccess { get; set; } = DateTime.UtcNow;
    public Task<HealthCheckResult> CheckHealthAsync(HealthCheckContext _, CancellationToken __)
        => Task.FromResult(
            DateTime.UtcNow - LastSuccess > TimeSpan.FromMinutes(5)
                ? HealthCheckResult.Unhealthy("No successful run in >5 min")
                : HealthCheckResult.Healthy());
}
